;(function () {
  if (typeof window === "undefined" || window.__PLAYERJS_PROGRESS_BRIDGE__) return

  window.__PLAYERJS_PROGRESS_BRIDGE__ = {
    attach(player, id) {
      let disposed = false
      let lastTime = -1
      let lastDuration = -1

      const readSnapshot = () => {
        const time = Number(player?.api?.("time") || 0)
        const duration = Number(player?.api?.("duration") || 0)
        return { id, time, duration }
      }

      const emit = (type) => {
        const detail = { type, ...readSnapshot() }
        window.dispatchEvent(new CustomEvent("playerjs-bridge", { detail }))
      }

      const interval = window.setInterval(() => {
        if (disposed) return
        const snapshot = readSnapshot()

        if (
          Number.isFinite(snapshot.duration) &&
          snapshot.duration > 0 &&
          (snapshot.time !== lastTime || snapshot.duration !== lastDuration)
        ) {
          lastTime = snapshot.time
          lastDuration = snapshot.duration
          emit("progress")
        }
      }, 1000)

      return {
        dispose() {
          disposed = true
          window.clearInterval(interval)
        },
        emit,
      }
    },
  }
})()
